```class Solution {
public:
    string discountPrices(string sentence, int discount) {
        vector<string> words;
        stringstream ss(sentence);
        string word;
        while (ss >> word) {
            if (word[0] == '$') {
                double price = stod(word.substr(1));
                double discountedPrice = price * (1 - discount / 100.0);
                word = "$" + to_string(setprecision(2) << fixed << discountedPrice);
            }
            words.push_back(word);
        }
        string result;
        for (int i = 0; i < words.size(); i++) {
            result += words[i];
            if (i < words.size() - 1) {
                result += " ";
            }
        }
        return result;
    }
};```
